<?php
declare(strict_types=1);
require_once dirname(__DIR__,2).'/includes/academico_flujo.php';exigirRol(['usuario']);if(($_SERVER['REQUEST_METHOD']??'')!=='POST'||!validarTokenCsrf((string)($_POST['csrf_token']??''))){http_response_code(400);exit;}$id=filter_var($_POST['contenido_id']??0,FILTER_VALIDATE_INT,['options'=>['min_range'=>1]])?:0;$accion=(string)($_POST['accion']??'');$pdo=obtenerConexion();$archivos=[];
try{$pdo->beginTransaction();$q=$pdo->prepare("SELECT c.*,i.id inscripcion_id,i.usuario_id FROM contenidos c JOIN inscripciones_capacitacion i ON i.seccion_id=c.seccion_id AND i.asignatura_id=c.asignatura_id WHERE c.id=:c AND i.usuario_id=:u AND i.estado IN('inscrito','finalizado') AND c.estado='activo' AND c.activo=1 FOR UPDATE");$q->execute(['c'=>$id,'u'=>$_SESSION['usuario_id']]);$c=$q->fetch();if(!$c)throw new DomainException('El contenido no pertenece a tu sección.');if($accion==='completar'){if(in_array($c['tipo'],['actividad','evaluacion'],true))throw new DomainException('Este contenido requiere una entrega aprobada.');$pdo->prepare('INSERT INTO progreso_contenido(inscripcion_id,contenido_id,visto_at,completado_at,ultima_actividad_at) VALUES(:i,:c,NOW(),NOW(),NOW()) ON DUPLICATE KEY UPDATE visto_at=COALESCE(visto_at,NOW()),completado_at=NOW(),ultima_actividad_at=NOW()')->execute(['i'=>$c['inscripcion_id'],'c'=>$id]);$mensaje='Contenido marcado como estudiado.';}elseif($accion==='entregar'){if(!in_array($c['tipo'],['actividad','evaluacion'],true))throw new DomainException('Este contenido no recibe entregas.');$comentario=trim(strip_tags((string)($_POST['comentario']??'')));$resultado=trim(strip_tags((string)($_POST['resultado']??'')));if($comentario===''||mb_strlen($comentario)>5000||mb_strlen($resultado)>10000)throw new DomainException('El comentario es obligatorio y debe tener un tamaño válido.');$q=$pdo->prepare('SELECT intento,estado FROM entregas_contenido WHERE contenido_id=:c AND estudiante_id=:u ORDER BY intento DESC LIMIT 1 FOR UPDATE');$q->execute(['c'=>$id,'u'=>$_SESSION['usuario_id']]);$prev=$q->fetch();if($prev&&!in_array($prev['estado'],['rechazada','requiere_correccion'],true))throw new DomainException('La entrega actual todavía no permite otro intento.');$intento=$prev?(int)$prev['intento']+1:1;$q=$pdo->prepare("INSERT INTO entregas_contenido(contenido_id,estudiante_id,asignatura_id,seccion_id,intento,comentario,resultado,estado,enviado_at) VALUES(:c,:u,:a,:s,:i,:comentario,:resultado,'enviada',NOW())");$q->execute(['c'=>$id,'u'=>$_SESSION['usuario_id'],'a'=>$c['asignatura_id'],'s'=>$c['seccion_id'],'i'=>$intento,'comentario'=>$comentario,'resultado'=>$resultado?:null]);$entrega=(int)$pdo->lastInsertId();if(isset($_FILES['evidencias']['name'])&&is_array($_FILES['evidencias']['name'])){if(count(array_filter($_FILES['evidencias']['name']))>5)throw new DomainException('Solo se permiten cinco evidencias por intento.');foreach($_FILES['evidencias']['name'] as$k=>$nombre){if(($_FILES['evidencias']['error'][$k]??UPLOAD_ERR_NO_FILE)===UPLOAD_ERR_NO_FILE)continue;$_FILES['_evidencia']=['name'=>$nombre,'type'=>$_FILES['evidencias']['type'][$k]??'','tmp_name'=>$_FILES['evidencias']['tmp_name'][$k]??'','error'=>$_FILES['evidencias']['error'][$k]??UPLOAD_ERR_NO_FILE,'size'=>$_FILES['evidencias']['size'][$k]??0];$f=guardarArchivoAcademico('_evidencia','evidencias','evidencia');$archivos[]=$f['relpath'];$pdo->prepare('INSERT INTO entrega_evidencias(entrega_id,archivo_relpath,archivo_nombre,archivo_mime,archivo_tamano) VALUES(:e,:r,:n,:m,:t)')->execute(['e'=>$entrega,'r'=>$f['relpath'],'n'=>$f['nombre'],'m'=>$f['mime'],'t'=>$f['tamano']]);}unset($_FILES['_evidencia']);}$pdo->prepare('INSERT INTO progreso_contenido(inscripcion_id,contenido_id,visto_at,ultima_actividad_at) VALUES(:i,:c,NOW(),NOW()) ON DUPLICATE KEY UPDATE visto_at=COALESCE(visto_at,NOW()),ultima_actividad_at=NOW()')->execute(['i'=>$c['inscripcion_id'],'c'=>$id]);crearNotificacionAtenea(['usuario_id'=>(int)$c['docente_id'],'created_by'=>$_SESSION['usuario_id'],'tipo'=>'entrega_nueva','categoria'=>'academico','nivel'=>'informacion','titulo'=>'Nueva entrega para revisar','descripcion'=>$c['titulo'].' · intento '.$intento,'url'=>atenea_url('src/docente/entregas.php'),'idempotency_key'=>'entrega:'.$entrega],$pdo);registrarAuditoria(['actor_user_id'=>$_SESSION['usuario_id'],'event_type'=>'academic.submission.sent','module'=>'academic','entity_type'=>'submission','entity_id'=>$entrega,'action'=>'create','result'=>'success','description'=>'Estudiante envió una entrega para su sección.'],$pdo);$mensaje='Entrega enviada para revisión.';}else throw new DomainException('Acción inválida.');$pdo->commit();$_SESSION['portal_flash']=['tipo'=>'success','mensaje'=>$mensaje];}catch(Throwable$e){if($pdo->inTransaction())$pdo->rollBack();foreach($archivos as$r){$p=rutaPrivadaAcademica($r);if($p)unlink($p);}$_SESSION['portal_flash']=['tipo'=>'danger','mensaje'=>$e instanceof DomainException?$e->getMessage():'No fue posible completar la acción.'];}header('Location:contenido.php?id='.$id);
